(96, 'Header', 'header', '', '2026-02-22 10:47:14', '2026-04-13 19:03:40', 54, '{\"theme\": \"light\", \"logo_alt\": \"Логотип сайта\", \"logo_link\": \"/\", \"logo_path\": \"uploads/images/html_blocks/DefaultHeaderBlock/logo_path_699adeb204ec6.png\", \"site_name\": \"Мой блог на BloggyCMS\", \"search_page\": \"/search\", \"show_search\": 1, \"show_shadow\": 1, \"main_menu_id\": \"17\", \"header_height\": \"sm\", \"sticky_header\": 1, \"container_type\": \"container-fluid\", \"show_site_name\": 1, \"profile_menu_id\": \"18\", \"mobile_breakpoint\": 992, \"search_placeholder\": \"Поиск...\"}', '[]', '[\"templates/default/front/assets/html_blocks/DefaultHeaderBlock/js/header.js\"]', '', '', 'default'),
(99, 'Hero', 'hero', '', '2026-02-27 23:01:33', '2026-03-16 19:04:36', 55, '{\"align\": \"left\", \"badge\": \"Блоггер-разработчик\", \"image\": \"uploads/images/html_blocks/DefaultHeroBlock/image_69a7b84e2b952.jpg\", \"theme\": \"light\", \"title\": \"С нуля до блога за один вечер\", \"buttons\": [{\"url\": \"/posts\", \"text\": \"Читать блог\"}, {\"url\": \"/page/moi-uslugi\", \"text\": \"Мои услуги\"}], \"description\": \"Привет! Я только что установила BloggyCMS и уже пишу этот текст. Дальше — расскажу о рефакторинге, архитектуре, PSR-стандартах и о том, как не скатиться в поддержку legacy-кода. Погнали!\", \"image_style\": \"circle\", \"padding_top\": \"80\", \"accent_color\": \"#0D6EFD\", \"image_position\": \"right\", \"padding_bottom\": \"80\"}', '[\"templates/default/front/assets/html_blocks/DefaultHeroBlock/css/hero-modern.css\"]', '[]', '', '', 'default'),
(101, 'breadcrumbs', 'breadcrumbs', '', '2026-03-02 21:20:15', '2026-03-15 20:01:56', 56, '{\"alignment\": \"left\", \"home_icon\": \"bs:house-door\", \"separator\": \"chevron\", \"show_home\": 1, \"show_current\": 1, \"enable_schema\": 1, \"hide_on_front\": 1, \"custom_css_class\": \"\"}', '[]', '[]', '', '', 'default'),
(102, 'Мои услуги', 'services', '', '2026-03-04 05:45:59', '2026-03-16 19:04:26', 57, '{\"align\": \"center\", \"badge\": \"Что я делаю\", \"theme\": \"light\", \"title\": \"Превращаю сложные задачи <span class=\\\"highlight\\\">в чистый код</span>\", \"buttons\": [{\"url\": \"/cdfhdgjh\", \"text\": \"Подробнее об услугах\"}, {\"url\": \"/jdjkfgfg\", \"text\": \"Обсудить проект\"}], \"columns\": \"3\", \"services\": [{\"image\": \"uploads/images/html_blocks/DefaultServicesBlock/repeater/services/services_0_image_69a7ca1792922.png\", \"price\": \"\", \"title\": \"Разработка на PHP\", \"description\": \"Современный PHP 8.x, PSR-стандарты, SOLID, паттерны проектирования. Пишу код, который легко поддерживать и масштабировать.\"}, {\"image\": \"uploads/images/html_blocks/DefaultServicesBlock/repeater/services/services_1_image_69a8181fafb23.png\", \"price\": \"\", \"title\": \"Рефакторинг legacy\", \"description\": \"Привожу в порядок устаревший код: внедряю архитектуру, покрываю тестами, оптимизирую производительность без остановки проекта.\"}, {\"image\": \"uploads/images/html_blocks/DefaultServicesBlock/repeater/services/services_2_image_69a8181faff63.png\", \"price\": \"\", \"title\": \"Архитектура проектов\", \"description\": \"Проектирую масштабируемые решения: от выбора стека до построения микросервисной архитектуры. Доменный-ориентированный дизайн (DDD).\"}], \"description\": \"Специализируюсь на высоконагруженных проектах и рефакторинге legacy-кода. Помогаю бизнесу расти без технических долгов.\", \"padding_top\": \"80\", \"accent_color\": \"#2563eb\", \"padding_bottom\": \"80\", \"card_background\": \"#EEEEEE\"}', '[\"templates/default/front/assets/html_blocks/DefaultServicesBlock/css/services.css\"]', '[]', '', '', 'default'),
(104, 'Посты', 'posts', '', '2026-03-04 21:36:27', '2026-03-16 19:04:17', 59, '{\"align\": \"center\", \"badge\": \"Блог\", \"theme\": \"light\", \"title\": \"Читайте <span class=\\\"highlight\\\">свежие статьи</span>\", \"columns\": \"3\", \"order_by\": \"created_at DESC\", \"custom_id\": \"\", \"show_date\": \"1\", \"show_views\": \"1\", \"date_format\": \"relative\", \"description\": \"Делюсь опытом, мыслями и инсайтами о разработке, архитектуре и не только.\", \"padding_top\": \"80\", \"posts_count\": \"3\", \"show_author\": \"1\", \"accent_color\": \"#2563eb\", \"show_excerpt\": \"1\", \"show_category\": \"1\", \"excerpt_length\": \"100\", \"padding_bottom\": \"80\", \"show_read_time\": \"1\", \"card_background\": \"\", \"custom_css_class\": \"\", \"filter_by_category\": \"0\", \"show_featured_image\": \"1\", \"exclude_current_post\": \"1\"}', '[\"templates/default/front/assets/html_blocks/DefaultLatestPostsBlock/css/latest-posts.css\"]', '[]', '', '', 'default'),
