(106, 'Теги', 'tags', '', '2026-03-04 23:03:22', '2026-03-16 19:03:58', 61, '{\"align\": \"center\", \"badge\": \"Теги\", \"limit\": \"20\", \"theme\": \"light\", \"title\": \"Навигация по <span class=\\\"highlight\\\">тегам</span>\", \"columns\": \"3\", \"order_by\": \"name ASC\", \"custom_id\": \"\", \"min_posts\": \"1\", \"show_icon\": \"1\", \"image_size\": \"md\", \"description\": \"Исследуйте статьи по интересующим темам\", \"exclude_ids\": \"\", \"image_style\": \"thumbnail\", \"include_ids\": \"\", \"padding_top\": \"80\", \"accent_color\": \"#2563eb\", \"image_shadow\": \"0\", \"display_style\": \"grid\", \"image_rounded\": \"1\", \"gradient_cards\": \"0\", \"padding_bottom\": \"80\", \"card_background\": \"\", \"show_post_count\": \"1\", \"custom_css_class\": \"\"}', '[\"templates/default/front/assets/html_blocks/TagsBlock/css/tags-block.css\"]', '[]', '', '', 'default'),
(107, 'Подвал блога', 'footer', '', '2026-03-10 00:28:40', '2026-03-16 19:03:47', 62, '{\"logo_alt\": \"Логотип сайта\", \"logo_path\": \"uploads/images/html_blocks/DefaultFooterBlock/logo_path_69b048179d9f3.png\", \"site_name\": \"Блог PHP-программиста\", \"text_color\": \"#9ca3af\", \"padding_top\": 80, \"accent_color\": \"#DC3545\", \"footer_links\": [{\"url\": \"/page/politika-konfidencialnosti\", \"title\": \"Политика конфиденциальности\", \"target\": \"_self\"}, {\"url\": \"/page/pravila-bloga\", \"title\": \"Правила блога\", \"target\": \"_self\"}], \"menu_1_title\": \"Навигация\", \"menu_2_title\": \"Информация\", \"social_links\": [{\"url\": \"https://t.me\", \"network\": \"telegram\"}, {\"url\": \"https://vk.com\", \"network\": \"vk\"}, {\"url\": \"https://github.com\", \"network\": \"github\"}, {\"url\": \"https://ok.ru\", \"network\": \"odnoklassniki\"}], \"contact_email\": \"hello@bloggy.su\", \"contact_phone\": \"\", \"footer_menu_1\": \"19\", \"footer_menu_2\": \"20\", \"heading_color\": \"#FFFFFF\", \"show_contacts\": 1, \"contacts_title\": \"Свяжитесь со мной\", \"copyright_text\": \"© 2026 Блог PHP-программиста\", \"padding_bottom\": 40, \"contact_address\": \"\", \"show_categories\": 1, \"background_color\": \"#111827\", \"categories_count\": 5, \"categories_style\": \"pills\", \"categories_title\": \"Категории\", \"show_recent_tags\": 1, \"site_description\": \"Современная CMS для блогов и публикаций\", \"recent_tags_count\": 5, \"recent_tags_title\": \"Популярные теги\", \"show_recent_posts\": 1, \"recent_posts_count\": 3, \"recent_posts_title\": \"Последние посты\", \"categories_show_count\": 1}', '[\"templates/default/front/assets/html_blocks/DefaultFooterBlock/css/footer.css\"]', '[]', '', '', 'default');
