INSERT INTO `{#}posts` (`id`, `title`, `short_description`, `slug`, `category_id`, `user_id`, `status`, `allow_comments`, `featured_image`, `meta_description`, `seo_title`, `meta_keywords`, `created_at`, `updated_at`, `password_protected`, `password`, `show_to_groups`, `hide_from_groups`, `views`, `rating`, `likes_count`) VALUES
(136, 'Пишем Hello world с нуля на PHP', 'Привет, начинающий пхп-шник! Сегодня мы с тобой совершим невероятное путешествие в мир веб-разработки. Мы напишем программу, которая изменит твою жизнь, заставит твоих родителей гордиться тобой, а кота — смотреть на тебя с уважением. Да-да, ты уже догадался — мы будем писать Hello World на PHP!', 'pishem-hello-world-s-nulya-na-php', 35, 1, 'published', 1, '69ac6bd6ed84d_85562d79ff5cd98affde0e96f9c5b4b4.jpg', 'Пошаговое руководство по созданию первой программы на PHP. Установка локального сервера, синтаксис, переменные, функции и лучшие практики. Для тех, кто хочет начать изучать веб-разработку.', 'Как написать Hello World на PHP: полное руководство для начинающих с примерами', NULL, '2026-03-07 18:20:00', '2026-03-13 21:49:20', 0, '123', '[\"\"]', NULL, 48, 0, 2),
(137, '«Реальные пацаны»: почему спустя 10+ лет этот сериал остается недосягаемым шедевром (и при чем тут программисты)', 'Знаете, есть такое понятие — «культурный код». Для кого-то это Тарантино, для кого-то Бергман. А для меня (и, уверен, для многих из вас) — это сериал про Пермь, гопников и Коляна.', 'realnye-pacany-pochemu-spustya-10-let-etot-serial-ostaetsya-nedosyagaemym-shedevrom-i-pri-chem-tut-programmisty', 36, 1, 'published', 1, '69b51a15b2d2d_1920x.jpg', '', '', NULL, '2026-03-14 08:13:00', '2026-03-15 21:57:10', 0, '', NULL, NULL, 7, 0, 1),
(138, 'Чего ждать от PHP через 5 лет? Эволюция, которую мы заслужили', 'Каждый раз, когда в IT-тусовке заходит речь о PHP, в комментариях обязательно находится человек в каске с надписью «PHP мертв». Давайте сразу договоримся: PHP умирает последние лет 10, но при этом до сих пор кормит около 75% мирового веба (включая WordPress, Wikipedia и Etsy).', 'chego-zhdat-ot-php-cherez-5-let-evolyuciya-kotoruyu-my-zasluzhili', 34, 1, 'published', 1, '69b836c79a09e_gX8p-YigSdCs2cv5UPlsJA@2k.webp', '', '', NULL, '2026-03-16 16:53:00', '2026-03-16 17:03:04', 0, '', NULL, NULL, 2, 0, 0);
INSERT INTO `{#}post_block_settings` (`id`, `system_name`, `enable_in_posts`, `enable_in_pages`, `template`, `created_at`, `updated_at`) VALUES
(1, 'HeaderBlock', 1, 1, '<{level} class=\"post-block-header {alignment} {custom_class}\"{style}>{text}</{level}>', '2025-10-29 21:32:53', '2026-03-07 14:25:50'),
(2, 'QuoteBlock', 1, 1, '\"<blockquote>\\r\\n<p>{text}\\r\\n<cite>{author}</cite></p>\\r\\n</blockquote>\"', '2025-10-29 21:43:45', '2025-11-22 12:45:26'),
(3, 'TextBlock', 1, 1, '<p class = \"her {custom_class} {text_align} {font_size} {line_height}\">{content}</p>', '2025-10-29 21:44:09', '2026-03-07 14:33:03'),
(4, 'ListBlock', 1, 1, '\"<{list_type} class = \\\"{custom_class}\\\">\\r\\n  {list_items}\\r\\n\\t<li>\\r\\n\\t\\t{item_text}\\r\\n\\t</li>\\r\\n\\t{/list_items}\\r\\n</{list_type}>\"', '2025-10-29 22:12:39', '2026-01-17 20:05:43'),
(5, 'CodeBlock', 1, 1, '\"<div class=\\\"code-block-wrapper {custom_class}\\\">\\r\\n    <div class=\\\"code-header\\\">\\r\\n        <div class=\\\"code-meta\\\">\\r\\n            {language_badge}\\r\\n            {filename}\\r\\n        </div>\\r\\n        <div class=\\\"code-actions\\\">\\r\\n            {copy_button}\\r\\n        </div>\\r\\n    </div>\\r\\n    <div class=\\\"code-container\\\">\\r\\n        <pre class=\\\"{line_numbers}\\\" data-language=\\\"{language}\\\"><code class=\\\"language-{language}\\\">{code}</code></pre>\\r\\n    </div>\\r\\n</div>\"', '2025-11-02 15:27:07', '2026-01-17 12:54:41'),
(6, 'ImageBlock', 1, 1, '<div class=\"post-block-image {alignment} {custom_class}\">\r\n    <figure class=\"image-figure\">\r\n        <img src=\"{image_url}\" \r\n             alt=\"{alt_text}\" \r\n             class=\"img-fluid {image_class}\"\r\n             {width_attr}\r\n             {height_attr}\r\n             loading=\"lazy\">\r\n        {caption}\r\n    </figure>\r\n</div>', '2025-11-02 15:35:02', '2026-03-07 15:00:27'),
(7, 'GalleryBlock', 1, 1, '\"<div class=\\\"row row-cols-2 row-cols-sm-3 g-3 g-xl-4\\\">\\r\\n    {gallery_items}\\r\\n    <div class=\\\"col\\\">\\r\\n        <a class=\\\"hover-effect-scale hover-effect-opacity position-relative d-flex rounded overflow-hidden\\\" \\r\\n           href=\\\"{image_url}\\\" \\r\\n           data-glightbox \\r\\n           data-gallery=\\\"image-gallery\\\">\\r\\n            <i class=\\\"fi-zoom-in hover-effect-target fs-3 text-white position-absolute top-50 start-50 translate-middle opacity-0 z-2\\\"></i>\\r\\n            <span class=\\\"hover-effect-target position-absolute top-0 start-0 w-100 h-100 bg-black bg-opacity-25 opacity-0 z-1\\\"></span>\\r\\n            <div class=\\\"ratio ratio-1x1 hover-effect-target bg-body-tertiary rounded\\\">\\r\\n                <img src=\\\"{image_url}\\\" alt=\\\"{alt_text}\\\" class=\\\"w-100 h-100 object-fit-cover\\\">\\r\\n            </div>\\r\\n        </a>\\r\\n    </div>\\r\\n    {/gallery_items}\\r\\n</div>\"', '2025-11-02 15:36:02', '2026-01-17 14:07:08'),
(8, 'ButtonBlock', 1, 1, '<a href=\"{url}\" class=\"btn btn-primary\" target = \"{target}\">{icon_before} {text}</a>', '2025-11-02 22:20:11', '2026-03-16 17:14:21'),
(9, 'SpoilerBlock', 1, 1, '\"<div class=\\\"post-block-spoiler {custom_class}\\\">\\r\\n    <div class=\\\"spoiler-header\\\">\\r\\n        <button type=\\\"button\\\" class=\\\"spoiler-toggle {icon_position}\\\" data-bs-toggle=\\\"collapse\\\" data-bs-target=\\\"#spoiler-{block_id}\\\">\\r\\n            {icon_before}\\r\\n            <span class=\\\"spoiler-title\\\">{title}</span>\\r\\n            {icon_after}\\r\\n        </button>\\r\\n    </div>\\r\\n    <div class=\\\"spoiler-content collapse {show_default}\\\" id=\\\"spoiler-{block_id}\\\">\\r\\n        <div class=\\\"spoiler-body\\\">\\r\\n            {content}\\r\\n        </div>\\r\\n    </div>\\r\\n</div>\"', '2025-11-02 22:23:32', '2026-01-17 22:59:21'),
(10, 'ContentBlockPostBlock', 1, 1, '\"{content_block_html}\"', '2025-11-03 12:08:52', '2026-01-16 21:24:38'),
(11, 'PostBlockPostBlock', 1, 1, '\"<div class=\\\"card post-block-post\\\">\\r\\n    <div class=\\\"row g-0\\\">\\r\\n        {if-image}\\r\\n        <div class=\\\"col-md-4\\\">\\r\\n            <img src=\\\"{featured_image}\\\" class=\\\"img-fluid rounded-start\\\" alt=\\\"{post_title}\\\">\\r\\n        </div>\\r\\n        <div class=\\\"col-md-8\\\">\\r\\n        {/if-image}\\r\\n        {if-not-image}\\r\\n        <div class=\\\"col-12\\\">\\r\\n        {/if-not-image}\\r\\n            <div class=\\\"card-body\\\">\\r\\n                <h5 class=\\\"card-title\\\">\\r\\n                    <a href=\\\"{post_url}\\\" class=\\\"text-decoration-none\\\">{post_title}</a>\\r\\n                </h5>\\r\\n                <div class=\\\"card-text mb-2\\\">\\r\\n                    <small class=\\\"text-muted\\\">\\r\\n                        <i class=\\\"bi bi-person me-1\\\"></i>{author_name} | \\r\\n                        <i class=\\\"bi bi-calendar me-1\\\"></i>{post_date} | \\r\\n                        <i class=\\\"bi bi-eye me-1\\\"></i>{views_count}\\r\\n                    </small>\\r\\n                </div>\\r\\n                <div class=\\\"card-text\\\">\\r\\n                    <span class=\\\"badge bg-secondary\\\">{category_name}</span>\\r\\n                </div>\\r\\n            </div>\\r\\n        </div>\\r\\n    </div>\\r\\n</div>\"', '2025-11-24 11:24:21', '2025-11-24 14:07:53'),
(12, 'VideoBlock', 1, 1, '<div class=\"post-block-video {custom_class}\">\r\n    <div class=\"video-wrapper\">\r\n        {video_embed}\r\n    </div>\r\n    {caption_html}\r\n</div>', '2025-11-24 12:05:03', '2026-04-13 21:52:24'),
(13, 'ImageWithTextBlock', 1, 1, '\"<section class=\\\"section bg-white\\\">\\r\\n    <div class=\\\"container\\\">\\r\\n        <div class=\\\"row justify-content-start justify-content-lg-between align-items-center\\\">\\r\\n            <div class=\\\"col-xl-5 col-lg-6 has-anim visible\\\">\\r\\n                <img loading=\\\"lazy\\\" class=\\\"img-fluid {image_class}\\\" src=\\\"{image_url}\\\" alt=\\\"{alt_text}\\\">\\r\\n            </div>\\r\\n            <div class=\\\"col-lg-6 mt-5 mt-lg-0\\\">\\r\\n                <h2 class=\\\"h3 text-dark mb-3 has-anim fade visible\\\">{title}</h2>\\r\\n                <p class=\\\"lead text-dark mb-3 has-anim fade visible\\\">{text_content}</p>\\r\\n            </div>\\r\\n        </div>\\r\\n    </div>\\r\\n</section>\"', '2026-01-19 06:36:15', '2026-02-21 17:03:53'),
(14, 'CustomHtmlBlock', 1, 1, '\"{html_content}\"', '2026-02-01 04:00:35', '2026-02-01 04:00:43'),
(15, 'AlertBlock', 1, 1, '\"<div class=\\\"alert alert-{type} {dismissible_class} {custom_class}\\\" role=\\\"alert\\\" {aria_live}>\\r\\n    {icon}\\r\\n    <div class=\\\"alert-content\\\">\\r\\n        <div class=\\\"alert-title\\\">{title}</div>\\r\\n        <div class=\\\"alert-body\\\">{content}</div>\\r\\n    </div>\\r\\n    {dismiss_button}\\r\\n</div>\"', '2026-02-06 12:35:42', '2026-02-06 12:36:25'),
(17, 'AudioBlock', 1, 1, '<div class=\"post-block-audio {custom_class}\">\r\n<div class=\"custom-audio-player\" data-audio-player>\r\n    <audio class=\"audio-source\" preload=\"metadata\">\r\n        <source src=\"{src_mp3}\" type=\"audio/mpeg\">\r\n    </audio>\r\n    <div class=\"audio-player-container\">\r\n        <button type=\"button\" class=\"play-pause-btn\" data-play-pause>\r\n            <svg class=\"play-icon\" viewBox=\"0 0 24 24\" width=\"24\" height=\"24\">\r\n                <path fill=\"currentColor\" d=\"M8 5v14l11-7z\"/>\r\n            </svg>\r\n            <svg class=\"pause-icon\" viewBox=\"0 0 24 24\" width=\"24\" height=\"24\" style=\"display: none;\">\r\n                <path fill=\"currentColor\" d=\"M6 19h4V5H6v14zm8-14v14h4V5h-4z\"/>\r\n            </svg>\r\n        </button>\r\n        <div class=\"audio-info\">\r\n            <div class=\"audio-progress-container\" data-progress-container>\r\n                <div class=\"audio-progress\" data-progress></div>\r\n                <div class=\"audio-progress-buffered\" data-buffered></div>\r\n                <input type=\"range\" class=\"audio-progress-slider\" data-progress-slider min=\"0\" max=\"100\" step=\"0.1\" value=\"0\">\r\n            </div>\r\n            <div class=\"audio-time\">\r\n                <span class=\"current-time\" data-current-time>0:00</span>\r\n                <span class=\"separator\">/</span>\r\n                <span class=\"duration\" data-duration>0:00</span>\r\n            </div>\r\n        </div>\r\n        <div class=\"audio-volume-container\" data-volume-container>\r\n            <button type=\"button\" class=\"volume-btn\" data-volume-btn>\r\n                <svg class=\"volume-high-icon\" viewBox=\"0 0 24 24\" width=\"20\" height=\"20\">\r\n                    <path fill=\"currentColor\" d=\"M3 9v6h4l5 5V4L7 9H3zm13.5 3c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77z\"/>\r\n                </svg>\r\n                <svg class=\"volume-low-icon\" viewBox=\"0 0 24 24\" width=\"20\" height=\"20\" style=\"display: none;\">\r\n                    <path fill=\"currentColor\" d=\"M5 9v6h4l5 5V4L9 9H5z\"/>\r\n                </svg>\r\n                <svg class=\"volume-muted-icon\" viewBox=\"0 0 24 24\" width=\"20\" height=\"20\" style=\"display: none;\">\r\n                    <path fill=\"currentColor\" d=\"M16.5 12c0-1.77-1.02-3.29-2.5-4.03v8.05c1.48-.73 2.5-2.25 2.5-4.02zM14 3.23v2.06c2.89.86 5 3.54 5 6.71s-2.11 5.85-5 6.71v2.06c4.01-.91 7-4.49 7-8.77s-2.99-7.86-7-8.77z\"/>\r\n                </svg>\r\n            </button>\r\n            <div class=\"volume-slider-container\">\r\n                <input type=\"range\" class=\"volume-slider\" data-volume-slider min=\"0\" max=\"100\" value=\"100\">\r\n            </div>\r\n        </div>\r\n    </div>\r\n</div>\r\n{caption_html}\r\n</div>', '2026-04-13 21:49:21', '2026-04-13 21:50:14');
