INSERT INTO `{#}settings` (`id`, `group_key`, `settings`, `created_at`, `updated_at`) VALUES
(2, 'general', '{\"site_name\": \"Блог PHP-программиста\", \"date_format\": \"d.m.Y\", \"site_author\": \"PHP-программист\", \"time_format\": \"H:i\", \"site_tagline\": \"Пишу код с утками\", \"contact_email\": \"developer@site.com\", \"meta_keywords\": \"программирование, разработка, PHP, mysql, css, javascript, HTML\", \"enable_sitemap\": \"1\", \"site_description\": \"В своем блоге я рассказываю о разработке на PHP и разработке сайтов\", \"enable_robots_txt\": \"1\", \"maintenance_message\": \"Сайт временно недоступен. Ведутся технические работы.\"}', '2025-03-22 09:19:20', '2026-02-21 17:08:36'),
(9, 'site', '{\"base_url\": \"http://bloggy3\", \"site_template\": \"default\", \"template_backups_count\": \"5\", \"template_backups_cleanup\": \"auto\", \"template_backups_enabled\": \"0\"}', '2025-04-07 18:28:48', '2026-02-21 19:36:17'),
(23, 'blocks', '{\"list\": {\"enabled\": \"1\", \"template\": \"<{type} class=\'list-block list-{style}\'>{items}</{type}>\", \"disabled_fields\": []}, \"text\": {\"enabled\": \"1\", \"template\": \"<p class=\'text-dark mb-4 fs-lg\'>{text}</p>\", \"disabled_fields\": []}, \"image\": {\"enabled\": \"1\", \"template\": \"<img src=\\\"{src}\\\" class=\\\"img-fluid rounded-4 mb-4\\\" alt=\\\"{alt}\\\">\", \"disabled_fields\": []}, \"quote\": {\"enabled\": \"1\", \"template\": \"<blockquote class=\\\"block-quote relative pt-8 pb-8 pl-20 overflow-hidden mb-4\\\">\\r\\n              <svg xmlns=\\\"http://www.w3.org/2000/svg\\\" width=\\\"49\\\" height=\\\"36\\\" viewBox=\\\"0 0 49 36\\\" class=\\\"fill-primary-light-950 dark:fill-primary-dark-950 opacity-20 absolute top-8 left-0\\\">\\r\\n                <path d=\\\"M10.5 0.5C16.2969 0.5 21 5.20312 21 11V21.5C21 29.2656 14.6562 35.5 7 35.5C5.03125 35.5 3.5 33.9688 3.5 32C3.5 30.1406 5.03125 28.5 7 28.5C10.8281 28.5 14 25.4375 14 21.5V20.9531C12.7969 21.2812 11.7031 21.5 10.5 21.5C4.59375 21.5 0 16.9062 0 11C0 5.20312 4.59375 0.5 10.5 0.5ZM49 11V21.5C49 29.2656 42.6562 35.5 35 35.5C33.0312 35.5 31.5 33.9688 31.5 32C31.5 30.1406 33.0312 28.5 35 28.5C38.8281 28.5 42 25.4375 42 21.5V20.9531C40.7969 21.2812 39.7031 21.5 38.5 21.5C32.5938 21.5 28 16.9062 28 11C28 5.20312 32.5938 0.5 38.5 0.5C44.2969 0.5 49 5.20312 49 11Z\\\" fill=\\\"#FFCF01\\\"></path>\\r\\n              </svg>\\r\\n              <span class=\\\"font-normal text-xl block mb-4\\\">{text}</span>\\r\\n              <cite>-- {author}</cite>\\r\\n            </blockquote>\", \"disabled_fields\": [\"source\", \"align\"]}, \"button\": {\"enabled\": \"1\", \"template\": \"<div class=\\\"button-block text-{align}\\\">\\r\\n    <a href=\\\"{url}\\\" {target} class=\\\"btn btn-{style} btn-{size} {full_width_class}\\\">\\r\\n        {text}\\r\\n    </a>\\r\\n</div>\", \"disabled_fields\": []}, \"header\": {\"enabled\": \"1\", \"template\": \"<{level} class=\'text-dark mb-4\' {style}>{text}</{level}>\", \"disabled_fields\": [\"color\"]}, \"gallery\": {\"enabled\": \"1\", \"template\": \"\\r\\n        <div class=\\\"gallery-block\\\">\\r\\n            <div class=\\\"gallery-grid\\\">\\r\\n                {images}\\r\\n            </div>\\r\\n        </div>\", \"disabled_fields\": []}, \"wysiwyg\": {\"enabled\": \"1\", \"template\": \"<div class=\'wysiwyg-content\'>{html}</div>\", \"disabled_fields\": []}, \"link_button\": {\"enabled\": \"1\", \"template\": \"<div class=\'link-button-block text-{align}\'>\\r\\n<a href=\'{url}\' class=\'btn btn-primary changeless btn-{size}\' {new_tab_attr}>\\r\\n{text}\\r\\n</a>\\r\\n</div>\", \"disabled_fields\": []}}', '2025-10-17 15:37:05', '2025-10-25 18:34:14'),
(27, 'controller_tags', '{\"show_info\": \"0\", \"tag_prefix\": \"#\", \"tags_order\": \"name\", \"default_tag_image\": \"69260b4b40293_hashtag.png\", \"max_tags_per_post\": \"5\", \"min_posts_to_show\": \"0\", \"cont_tags_in_front\": \"15\"}', '2025-11-25 19:55:24', '2026-02-23 11:08:12'),
