(33, 'controller_comments', '{\"z1\": \"Этот пост еще никто не обсуждал...\", \"z2\": \"Будьте первым, кто оставит комментарий!\", \"z3\": \"Раскрыть ветку\", \"z4\": \"На модерации\", \"z5\": \"Вы\", \"z6\": \"Ответить\", \"z7\": \"Редактировать\", \"z8\": \"Удалить\", \"z9\": \"Введите ваше имя\", \"z10\": \"Имя\", \"z11\": \"Email\", \"z12\": \"Введите ваш email\", \"z13\": \"Ваш email не будет опубликован\", \"z14\": \"Вы комментируете как\", \"z15\": \"Комментарий\", \"z16\": \"Напишите ваш комментарий...\", \"z17\": \"Комментарии\", \"z18\": \"Написать комментарий\", \"bg_badge\": \"#000000\", \"max_depth\": \"3\", \"icon_badge\": \"solid:code\", \"color_badge\": \"#f3f937\", \"emodji_list\": [{\"icon\": \"😀\"}, {\"icon\": \"😂\"}, {\"icon\": \"☺️\"}, {\"icon\": \"😍\"}, {\"icon\": \"😋\"}, {\"icon\": \"😎\"}, {\"icon\": \"🥳\"}, {\"icon\": \"😞\"}, {\"icon\": \"😫\"}, {\"icon\": \"😢\"}, {\"icon\": \"🤬\"}, {\"icon\": \"😱\"}, {\"icon\": \"😯\"}, {\"icon\": \"😴\"}, {\"icon\": \"🤧\"}, {\"icon\": \"❤️\"}, {\"icon\": \"🤟\"}, {\"icon\": \"👀\"}], \"show_emodji\": \"1\", \"show_groups\": \"1\", \"title_badge\": \"Dev\", \"show_admin_badge\": \"1\"}', '2026-01-24 16:16:45', '2026-01-27 20:12:55'),
